import React, { useState } from 'react';
import axios from 'axios';

const Auth = () => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [isLogin, setIsLogin] = useState(true);

  const handleSubmit = async (e) => {
    e.preventDefault();
    const url = isLogin ? '/api/auth/login' : '/api/auth/register';
    try {
      const res = await axios.post(`http://localhost:5000${url}`, { email, password });
      
      if (isLogin) {
        // Save the token for authentication [cite: 53]
        localStorage.setItem('token', res.data.token);

        // SAVE THE USER ID (This is what the Buy button needs!)
        localStorage.setItem('userId', res.data.user.id);
        
        // Save the verification status to Local Storage 
        localStorage.setItem('isVerified', res.data.user.isVerifiedSeller);
        
        // Save the user's email for the dashboard [cite: 96]
        localStorage.setItem('userEmail', res.data.user.email);
        
        alert('Logged in successfully!');
        // Redirect to the dashboard or marketplace [cite: 9, 30]
        window.location.href = '/dashboard'; 
      } else {
        alert('Registration complete! Please log in.');
        setIsLogin(true);
      }
    } catch (err) {
      alert('Authentication failed: ' + (err.response?.data || 'Server error'));
    }
  };

  return (
    <div className="auth-container">
      <h2>{isLogin ? 'Login' : 'Register'}</h2>
      <form onSubmit={handleSubmit}>
        <input type="email" placeholder="Email" onChange={(e) => setEmail(e.target.value)} required />
        <input type="password" placeholder="Password" onChange={(e) => setPassword(e.target.value)} required />
        <button type="submit">{isLogin ? 'Login' : 'Sign Up'}</button>
      </form>
      <button onClick={() => setIsLogin(!isLogin)}>
        Switch to {isLogin ? 'Register' : 'Login'}
      </button>
    </div>
  );
};

export default Auth;
